class Solution {
    public int calculate(String s) {
        int num = 0;
        int stack = 0;
        int sign = '+';
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (Character.isDigit(c)) {
                num = num * 10 + c - '0';
            }
            if ((!Character.isDigit(c) && c != ' ') || i == s.length() - 1) {
                if (sign == '+') {
                    stack += num;
                } else if (sign == '-') {
                    stack -= num;
                } else if (sign == '*') {
                    stack *= num;
                } else if (sign == '/') {
                    stack /= num;
                }
                sign = c;
                num = 0;
            }
        }
        return stack;
    }
}
